import{_ as s,o as a,c as n,Q as e}from"./chunks/framework.b6910bb2.js";const l="/vitePress-blob/assets/32.7a776143.jpg",p="/vitePress-blob/assets/31.baa6af05.png",o="/vitePress-blob/assets/18.84058b1a.png",t="/vitePress-blob/assets/23.c3f7cd8c.png",c="/vitePress-blob/assets/25.b2aee701.png",i="/vitePress-blob/assets/24.ee6c91cc.png",r="/vitePress-blob/assets/26.1018dc1c.png",d="/vitePress-blob/assets/27.af8a3392.png",u="/vitePress-blob/assets/28.2ec3a182.png",y="/vitePress-blob/assets/29.8153324c.png",h="/vitePress-blob/assets/33.fa3a5c5a.png",E="/vitePress-blob/assets/30.1bffaf1e.png",g="/vitePress-blob/assets/19.02dcdda6.png",b="/vitePress-blob/assets/20.cb0a263a.png",m="/vitePress-blob/assets/21.ae7c11ab.png",A="/vitePress-blob/assets/22.8421793f.png",B=JSON.parse('{"title":"Claude Code 中的 SubAgent","description":"","frontmatter":{},"headers":[],"relativePath":"guide/ai/Claude Code 中的 SubAgent.md","filePath":"guide/ai/Claude Code 中的 SubAgent.md","lastUpdated":1774602295000}'),k={name:"guide/ai/Claude Code 中的 SubAgent.md"},v=e('<h1 id="claude-code-中的-subagent" tabindex="-1">Claude Code 中的 SubAgent <a class="header-anchor" href="#claude-code-中的-subagent" aria-label="Permalink to &quot;Claude Code 中的 SubAgent&quot;">​</a></h1><p><img src="'+l+`" alt="SubAgent 图"></p><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>上一讲我们介绍了 Claude Code 的记忆系统，重点解决的是 Agent 的“失忆”问题，也就是如何通过记忆机制和 CLAUDE.md 让 Claude 持续保留关键上下文。</p><p>这一讲将讨论另一个在实际使用中非常常见的问题：当任务越来越复杂、输出越来越嘈杂、职责越来越分散时，单一 Agent 开始“降智”，该如何解决？</p><p>而这，正是 SubAgent 要解决的问题。</p><h2 id="为什么要有-subagent" tabindex="-1">为什么要有 SubAgent？ <a class="header-anchor" href="#为什么要有-subagent" aria-label="Permalink to &quot;为什么要有 SubAgent？&quot;">​</a></h2><p>SubAgent 的核心价值，不是“把一个 Agent 拆成很多个 Agent”这么简单，而是解决单一 Agent 在以下三个方面不断膨胀的问题：</p><ul><li>上下文</li><li>权限</li><li>职责</li></ul><p>举个非常常见的例子：</p><p>某天你让 Claude Code 帮你跑一个测试套件，终端输出了 500 行日志； 接着你又让它分析一段代码结构，又输出了 200 行结果； 然后你再让它修一个 bug，把上千行日志、代码片段和分析结果都堆进同一段对话里。</p><p>这时，你在询问其他问题，你会感觉 Claude Code 越来越“弱智”，但问题通常不在模型本身，而在于主对话的上下文已经被大量中间过程污染。真正重要的信息被稀释，Agent 的注意力自然也会开始分散。</p><p>SubAgent 的意义，就是把这些高噪声、高耦合、可拆分的任务切出去处理，将任务交由专门的子代理处理，让主 Agent 只接收经过整理的结论，而不是被完整过程淹没。</p><p>基于同样的思想，社区中也出现了许多类似的实践，比如：</p><ul><li><a href="https://github.com/cft0808/edict" target="_blank" rel="noreferrer">三省六部制多 Agent 设计理念</a></li><li><a href="https://github.com/anthropics/skills/blob/main/skills/skill-creator/SKILL.md" target="_blank" rel="noreferrer">skill-creator</a></li></ul><h2 id="如何编写一个-subagent" tabindex="-1">如何编写一个 SubAgent？ <a class="header-anchor" href="#如何编写一个-subagent" aria-label="Permalink to &quot;如何编写一个 SubAgent？&quot;">​</a></h2><p>从 <a href="https://code.claude.com/docs/zh-CN/sub-agents" target="_blank" rel="noreferrer">官方文档</a> 看出，Subagent 文件使用 YAML frontmatter 进行配置，后跟 Markdown 中的系统提示。</p><p>下面是一个简单的 code-reviewer SubAgent 文件示例：</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#E1E4E8;">---</span></span>
<span class="line"><span style="color:#85E89D;">name</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">code-reviewer</span></span>
<span class="line"><span style="color:#85E89D;">description</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">Reviews code for quality and best practices</span></span>
<span class="line"><span style="color:#85E89D;">tools</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">Read, Glob, Grep</span></span>
<span class="line"><span style="color:#85E89D;">model</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">sonnet</span></span>
<span class="line"><span style="color:#E1E4E8;">---</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E1E4E8;">You are a code reviewer. When invoked, analyze the code and provide</span></span>
<span class="line"><span style="color:#E1E4E8;">specific, actionable feedback on quality, security, and best practices.</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292E;">---</span></span>
<span class="line"><span style="color:#22863A;">name</span><span style="color:#24292E;">: </span><span style="color:#032F62;">code-reviewer</span></span>
<span class="line"><span style="color:#22863A;">description</span><span style="color:#24292E;">: </span><span style="color:#032F62;">Reviews code for quality and best practices</span></span>
<span class="line"><span style="color:#22863A;">tools</span><span style="color:#24292E;">: </span><span style="color:#032F62;">Read, Glob, Grep</span></span>
<span class="line"><span style="color:#22863A;">model</span><span style="color:#24292E;">: </span><span style="color:#032F62;">sonnet</span></span>
<span class="line"><span style="color:#24292E;">---</span></span>
<span class="line"></span>
<span class="line"><span style="color:#24292E;">You are a code reviewer. When invoked, analyze the code and provide</span></span>
<span class="line"><span style="color:#24292E;">specific, actionable feedback on quality, security, and best practices.</span></span></code></pre></div><p>这里我们简单的了解一下 subAgent 是由两部分组成的：</p><ul><li>YAML frontmatter：用来描述 subAgent 的元信息，包括名称、描述、工具权限、模型选择等</li><li>Prompt 模板：用来定义 subAgent 的角色、任务和输出格式等</li></ul><p>可以通过自然语言显示触发 code-reviewer 这个 SubAgent：</p><p><img src="`+p+`" alt="触发 code-reviewer SubAgent"></p><p>通过这个案例，可以把子代理理解为一个 “专职小助手”：</p><ul><li>它有自己的上下文窗口</li><li>它可以被授予独立的工具权限</li><li>它只负责某一类明确任务</li><li>它完成后把结果摘要带回给主 Agent</li></ul><p>从工程视角看，SubAgent 的价值主要体现在三点：</p><ul><li><strong>上下文隔离</strong></li><li><strong>权限约束</strong></li><li><strong>复用</strong></li></ul><h2 id="什么时候该用子代理" tabindex="-1">什么时候该用子代理？ <a class="header-anchor" href="#什么时候该用子代理" aria-label="Permalink to &quot;什么时候该用子代理？&quot;">​</a></h2><p>并不是所有任务都需要 SubAgent。判断标准很简单：</p><p>当你发现任务具备“<strong>高噪声、需要隔离、可拆分</strong>”这些特点时，就值得考虑引入子代理。</p><h3 id="_1-高噪声任务" tabindex="-1">1. 高噪声任务 <a class="header-anchor" href="#_1-高噪声任务" aria-label="Permalink to &quot;1. 高噪声任务&quot;">​</a></h3><p>典型场景包括：</p><ul><li>跑测试用例</li><li>分析错误日志</li><li>排查构建输出</li><li>检查大规模检索结果</li></ul><p>这类任务的共同点是：过程信息很多，但主 Agent 真正需要的往往只是结论。</p><h3 id="_2-有权限隔离要求的任务" tabindex="-1">2. 有权限隔离要求的任务 <a class="header-anchor" href="#_2-有权限隔离要求的任务" aria-label="Permalink to &quot;2. 有权限隔离要求的任务&quot;">​</a></h3><p>例如：</p><ul><li>代码审查</li><li>安全审计</li><li>只读数据库查询</li><li>配置检查</li></ul><p>这些任务通常不希望 Agent 修改代码或执行高风险操作，因此适合通过 SubAgent 严格约束工具权限。</p><h3 id="_3-可并行拆分的任务" tabindex="-1">3. 可并行拆分的任务 <a class="header-anchor" href="#_3-可并行拆分的任务" aria-label="Permalink to &quot;3. 可并行拆分的任务&quot;">​</a></h3><p>例如同时做下面三件事：</p><ul><li>跑测试</li><li>分析错误日志</li><li>做代码审查</li></ul><p>如果这些任务相互独立，没有直接依赖关系，那么就可以交给多个 SubAgent 并行处理，最后由主 Agent 统一汇总结果。</p><h3 id="_4-明确分阶段的流水线任务" tabindex="-1">4. 明确分阶段的流水线任务 <a class="header-anchor" href="#_4-明确分阶段的流水线任务" aria-label="Permalink to &quot;4. 明确分阶段的流水线任务&quot;">​</a></h3><p>例如修复一个 bug，通常会经历四个阶段：</p><ol><li>定位问题</li><li>分析原因</li><li>实施修复</li><li>验证结果</li></ol><p>这种任务的特点是阶段之间有依赖关系，上一个阶段的输出，会成为下一个阶段的输入，因此更适合按流水线方式编排多个子代理。</p><h3 id="不适合用子代理的情况" tabindex="-1">不适合用子代理的情况 <a class="header-anchor" href="#不适合用子代理的情况" aria-label="Permalink to &quot;不适合用子代理的情况&quot;">​</a></h3><p>如果任务需要用户频繁确认、不断交互式调整方向，那么通常不适合过度拆成子代理。因为这类任务的关键不在隔离执行，而在持续沟通。</p><blockquote><p>‼️ 重要原则：子代理应该由主 Agent 创建，不要在子代理内再创建新的子代理。</p></blockquote><h2 id="子代理配置文件详解" tabindex="-1">子代理配置文件详解 <a class="header-anchor" href="#子代理配置文件详解" aria-label="Permalink to &quot;子代理配置文件详解&quot;">​</a></h2><p>子代理文件一般位于 <code>.claude/subagents/</code> 目录下，通常是一个 Markdown 文件。</p><p>它通常由两部分组成：</p><ul><li>YAML frontmatter，用于描述元数据</li><li>Prompt 模板，用于定义角色、任务和输出格式</li></ul><p>例如：</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#E1E4E8;">---</span></span>
<span class="line"><span style="color:#85E89D;">name</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">code-reviewer</span></span>
<span class="line"><span style="color:#85E89D;">description</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">Review code for security issues and best practices. Use after code changes.</span></span>
<span class="line"><span style="color:#85E89D;">tools</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">Read, Grep, Glob</span></span>
<span class="line"><span style="color:#85E89D;">model</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">sonnet</span></span>
<span class="line"><span style="color:#E1E4E8;">---</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E1E4E8;">你是一个代码审查专家。</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E1E4E8;">当被调用时：</span></span>
<span class="line"></span>
<span class="line"><span style="color:#FFAB70;">1.</span><span style="color:#E1E4E8;"> 首先理解代码变更的范围</span></span>
<span class="line"><span style="color:#FFAB70;">2.</span><span style="color:#E1E4E8;"> 检查安全问题</span></span>
<span class="line"><span style="color:#FFAB70;">3.</span><span style="color:#E1E4E8;"> 检查代码规范</span></span>
<span class="line"><span style="color:#FFAB70;">4.</span><span style="color:#E1E4E8;"> 提供改进建议</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E1E4E8;">输出格式：</span></span>
<span class="line"><span style="color:#79B8FF;font-weight:bold;">## 审查结果</span></span>
<span class="line"><span style="color:#FFAB70;">-</span><span style="color:#E1E4E8;"> 安全问题：[</span><span style="color:#DBEDFF;text-decoration:underline;">列表</span><span style="color:#E1E4E8;">]</span></span>
<span class="line"><span style="color:#FFAB70;">-</span><span style="color:#E1E4E8;"> 规范问题：[</span><span style="color:#DBEDFF;text-decoration:underline;">列表</span><span style="color:#E1E4E8;">]</span></span>
<span class="line"><span style="color:#FFAB70;">-</span><span style="color:#E1E4E8;"> 建议：[</span><span style="color:#DBEDFF;text-decoration:underline;">列表</span><span style="color:#E1E4E8;">]</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292E;">---</span></span>
<span class="line"><span style="color:#22863A;">name</span><span style="color:#24292E;">: </span><span style="color:#032F62;">code-reviewer</span></span>
<span class="line"><span style="color:#22863A;">description</span><span style="color:#24292E;">: </span><span style="color:#032F62;">Review code for security issues and best practices. Use after code changes.</span></span>
<span class="line"><span style="color:#22863A;">tools</span><span style="color:#24292E;">: </span><span style="color:#032F62;">Read, Grep, Glob</span></span>
<span class="line"><span style="color:#22863A;">model</span><span style="color:#24292E;">: </span><span style="color:#032F62;">sonnet</span></span>
<span class="line"><span style="color:#24292E;">---</span></span>
<span class="line"></span>
<span class="line"><span style="color:#24292E;">你是一个代码审查专家。</span></span>
<span class="line"></span>
<span class="line"><span style="color:#24292E;">当被调用时：</span></span>
<span class="line"></span>
<span class="line"><span style="color:#E36209;">1.</span><span style="color:#24292E;"> 首先理解代码变更的范围</span></span>
<span class="line"><span style="color:#E36209;">2.</span><span style="color:#24292E;"> 检查安全问题</span></span>
<span class="line"><span style="color:#E36209;">3.</span><span style="color:#24292E;"> 检查代码规范</span></span>
<span class="line"><span style="color:#E36209;">4.</span><span style="color:#24292E;"> 提供改进建议</span></span>
<span class="line"></span>
<span class="line"><span style="color:#24292E;">输出格式：</span></span>
<span class="line"><span style="color:#005CC5;font-weight:bold;">## 审查结果</span></span>
<span class="line"><span style="color:#E36209;">-</span><span style="color:#24292E;"> 安全问题：[</span><span style="color:#032F62;text-decoration:underline;">列表</span><span style="color:#24292E;">]</span></span>
<span class="line"><span style="color:#E36209;">-</span><span style="color:#24292E;"> 规范问题：[</span><span style="color:#032F62;text-decoration:underline;">列表</span><span style="color:#24292E;">]</span></span>
<span class="line"><span style="color:#E36209;">-</span><span style="color:#24292E;"> 建议：[</span><span style="color:#032F62;text-decoration:underline;">列表</span><span style="color:#24292E;">]</span></span></code></pre></div><p>其中，YAML frontmatter 用来定义子代理的名称、职责、权限、模型和运行方式；正文部分则负责告诉子代理“该如何做”和“最终输出成什么样”。</p><h3 id="yaml-frontmatter-常见属性" tabindex="-1">YAML frontmatter 常见属性 <a class="header-anchor" href="#yaml-frontmatter-常见属性" aria-label="Permalink to &quot;YAML frontmatter 常见属性&quot;">​</a></h3><ul><li>name: 必填，子代理名称，例如 <code>code-reviewer</code></li><li>description: 必填，子代理描述，决定 Claude 在什么场景下会调用它</li><li>tools: 可选，工具白名单，例如 <code>Read, Grep, Glob</code></li><li>disallowedTools: 可选，工具黑名单，例如 <code>Write, Edit</code></li><li>model: 可选，模型名称，例如 <code>haiku / sonnet / opus / inherit</code></li><li>permissionMode: 可选，权限模式，例如 <code>default / acceptEdits / plan / dontAsk / bypassPermissions</code></li><li>skills: 可选，预加载技能，例如 <code>api-search / code-search</code></li><li>hooks: 可选，生命周期钩子，用于进一步约束工具行为</li></ul><p><img src="`+o+`" alt="YAML frontmatter 属性图"></p><p>下面重点看几个最关键的配置项。</p><h3 id="_1-description-决定何时被调用" tabindex="-1">1. description：决定何时被调用 <a class="header-anchor" href="#_1-description-决定何时被调用" aria-label="Permalink to &quot;1. description：决定何时被调用&quot;">​</a></h3><p>description 不是简单的一句介绍，它在很大程度上决定 Claude 会不会在合适的时机调用这个子代理。</p><p>好的 description 应该同时回答两个问题：</p><ul><li>这个子代理怎么做事</li><li>这个子代理应该在什么时候被使用</li></ul><p>例如：</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#79B8FF;font-weight:bold;"># 模糊写法</span></span>
<span class="line"><span style="color:#E1E4E8;">description: A code reviewer</span></span>
<span class="line"></span>
<span class="line"><span style="color:#79B8FF;font-weight:bold;"># 更好的写法</span></span>
<span class="line"><span style="color:#E1E4E8;">description: Review code changes for quality, security vulnerabilities, and best practices. Use proactively after code is modified or when the user asks for a code review.</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#005CC5;font-weight:bold;"># 模糊写法</span></span>
<span class="line"><span style="color:#24292E;">description: A code reviewer</span></span>
<span class="line"></span>
<span class="line"><span style="color:#005CC5;font-weight:bold;"># 更好的写法</span></span>
<span class="line"><span style="color:#24292E;">description: Review code changes for quality, security vulnerabilities, and best practices. Use proactively after code is modified or when the user asks for a code review.</span></span></code></pre></div><p>第一种写法只说了“它是什么”；第二种写法同时说明了“它做什么”和“什么时候用”，触发条件会更明确。</p><h3 id="_2-tools-vs-disallowedtools-白名单与黑名单" tabindex="-1">2. tools vs disallowedTools：白名单与黑名单 <a class="header-anchor" href="#_2-tools-vs-disallowedtools-白名单与黑名单" aria-label="Permalink to &quot;2. tools vs disallowedTools：白名单与黑名单&quot;">​</a></h3><p>这两个字段的作用是限定工具权限。</p><p>还是以 Code Review 为例，如果你不希望 Claude Code 修改文件，那么可以只允许它使用读取和搜索能力：</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#E1E4E8;">tools: Read, Grep, Glob</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292E;">tools: Read, Grep, Glob</span></span></code></pre></div><p>或者反过来，直接禁止写入相关工具：</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#E1E4E8;">disallowedTools: Write, Edit</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292E;">disallowedTools: Write, Edit</span></span></code></pre></div><p>通常不要同时使用两者，选一种表达方式即可，否则约束关系会变得不够直观。</p><h3 id="_3-model-模型怎么选" tabindex="-1">3. model：模型怎么选 <a class="header-anchor" href="#_3-model-模型怎么选" aria-label="Permalink to &quot;3. model：模型怎么选&quot;">​</a></h3><p>模型选择取决于任务复杂度：</p><ul><li>haiku：适合快速查找、轻量分析、简单转换</li><li>sonnet：适合中等复杂度的代码分析、设计判断、故障排查</li><li>opus：适合研究型任务、复杂推理和更高质量的综合分析</li></ul><p>如果不显式指定，通常会继承主窗口当前使用的模型。</p><h3 id="_4-permissionmode-权限模式" tabindex="-1">4. permissionMode：权限模式 <a class="header-anchor" href="#_4-permissionmode-权限模式" aria-label="Permalink to &quot;4. permissionMode：权限模式&quot;">​</a></h3><p>permissionMode 决定子代理在执行过程中的权限策略。</p><ul><li>default：默认模式，适用于大多数场景</li><li>acceptEdits：自动接受文件编辑，适合修复类任务</li><li>plan：只读探索模式，适合规划、审查、分析类任务</li><li>dontAsk：自动拒绝权限弹窗，适合严格受控的自动化场景</li><li>bypassPermissions：跳过所有权限检查，适合完全自动化场景</li></ul><p>例如，Code Review 子代理虽然可能会用到 Bash 做一些检索，但你仍然希望它保持只读，那么可以这样配置：</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#E1E4E8;">---</span></span>
<span class="line"><span style="color:#85E89D;">name</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">code-reviewer</span></span>
<span class="line"><span style="color:#85E89D;">tools</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">Read, Grep, Glob, Bash</span></span>
<span class="line"><span style="color:#85E89D;">permissionMode</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">plan</span></span>
<span class="line"><span style="color:#E1E4E8;">---</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292E;">---</span></span>
<span class="line"><span style="color:#22863A;">name</span><span style="color:#24292E;">: </span><span style="color:#032F62;">code-reviewer</span></span>
<span class="line"><span style="color:#22863A;">tools</span><span style="color:#24292E;">: </span><span style="color:#032F62;">Read, Grep, Glob, Bash</span></span>
<span class="line"><span style="color:#22863A;">permissionMode</span><span style="color:#24292E;">: </span><span style="color:#032F62;">plan</span></span>
<span class="line"><span style="color:#24292E;">---</span></span></code></pre></div><p>这里的关键点是：即便子代理拥有 Bash，也依旧处在只读探索模式中，不会被放开到任意修改文件的级别。</p><h3 id="_5-skills-为子代理预加载知识" tabindex="-1">5. skills：为子代理预加载知识 <a class="header-anchor" href="#_5-skills-为子代理预加载知识" aria-label="Permalink to &quot;5. skills：为子代理预加载知识&quot;">​</a></h3><p>如果某类任务总是依赖一组固定背景知识，可以通过 skills 字段预加载：</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#E1E4E8;">---</span></span>
<span class="line"><span style="color:#85E89D;">name</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">impact-analyzer</span></span>
<span class="line"><span style="color:#85E89D;">description</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">Analyze impact scope of code changes on the full call chain.</span></span>
<span class="line"><span style="color:#85E89D;">tools</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">Read, Grep, Glob, Bash</span></span>
<span class="line"><span style="color:#85E89D;">skills</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#9ECBFF;">chain-knowledge</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#9ECBFF;">recent-incidents</span></span>
<span class="line"><span style="color:#E1E4E8;">---</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292E;">---</span></span>
<span class="line"><span style="color:#22863A;">name</span><span style="color:#24292E;">: </span><span style="color:#032F62;">impact-analyzer</span></span>
<span class="line"><span style="color:#22863A;">description</span><span style="color:#24292E;">: </span><span style="color:#032F62;">Analyze impact scope of code changes on the full call chain.</span></span>
<span class="line"><span style="color:#22863A;">tools</span><span style="color:#24292E;">: </span><span style="color:#032F62;">Read, Grep, Glob, Bash</span></span>
<span class="line"><span style="color:#22863A;">skills</span><span style="color:#24292E;">:</span></span>
<span class="line"><span style="color:#24292E;">  - </span><span style="color:#032F62;">chain-knowledge</span></span>
<span class="line"><span style="color:#24292E;">  - </span><span style="color:#032F62;">recent-incidents</span></span>
<span class="line"><span style="color:#24292E;">---</span></span></code></pre></div><p>这样做的好处是，子代理在开始工作前就带着该领域的上下文进入任务，而不是每次都从零解释一遍。</p><h3 id="_6-hooks-进一步约束工具行为" tabindex="-1">6. hooks：进一步约束工具行为 <a class="header-anchor" href="#_6-hooks-进一步约束工具行为" aria-label="Permalink to &quot;6. hooks：进一步约束工具行为&quot;">​</a></h3><p>如果说 tools 控制的是“能用什么工具”，那么 hooks 控制的就是“工具能怎么用”。</p><p>例如：</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#E1E4E8;">---</span></span>
<span class="line"><span style="color:#85E89D;">name</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">db-reader</span></span>
<span class="line"><span style="color:#85E89D;">description</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">Execute read-only database queries.</span></span>
<span class="line"><span style="color:#85E89D;">tools</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">Bash</span></span>
<span class="line"><span style="color:#85E89D;">hooks</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#E1E4E8;">  </span><span style="color:#85E89D;">PreToolUse</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#E1E4E8;">    - </span><span style="color:#85E89D;">matcher</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">&quot;Bash&quot;</span></span>
<span class="line"><span style="color:#E1E4E8;">      </span><span style="color:#85E89D;">hooks</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#E1E4E8;">        - </span><span style="color:#85E89D;">type</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">command</span></span>
<span class="line"><span style="color:#E1E4E8;">          </span><span style="color:#85E89D;">command</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">&quot;./scripts/validate-readonly-query.sh&quot;</span></span>
<span class="line"><span style="color:#E1E4E8;">---</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292E;">---</span></span>
<span class="line"><span style="color:#22863A;">name</span><span style="color:#24292E;">: </span><span style="color:#032F62;">db-reader</span></span>
<span class="line"><span style="color:#22863A;">description</span><span style="color:#24292E;">: </span><span style="color:#032F62;">Execute read-only database queries.</span></span>
<span class="line"><span style="color:#22863A;">tools</span><span style="color:#24292E;">: </span><span style="color:#032F62;">Bash</span></span>
<span class="line"><span style="color:#22863A;">hooks</span><span style="color:#24292E;">:</span></span>
<span class="line"><span style="color:#24292E;">  </span><span style="color:#22863A;">PreToolUse</span><span style="color:#24292E;">:</span></span>
<span class="line"><span style="color:#24292E;">    - </span><span style="color:#22863A;">matcher</span><span style="color:#24292E;">: </span><span style="color:#032F62;">&quot;Bash&quot;</span></span>
<span class="line"><span style="color:#24292E;">      </span><span style="color:#22863A;">hooks</span><span style="color:#24292E;">:</span></span>
<span class="line"><span style="color:#24292E;">        - </span><span style="color:#22863A;">type</span><span style="color:#24292E;">: </span><span style="color:#032F62;">command</span></span>
<span class="line"><span style="color:#24292E;">          </span><span style="color:#22863A;">command</span><span style="color:#24292E;">: </span><span style="color:#032F62;">&quot;./scripts/validate-readonly-query.sh&quot;</span></span>
<span class="line"><span style="color:#24292E;">---</span></span></code></pre></div><p>这个例子中，db-reader 虽然拥有 Bash 权限，但每次执行 Bash 前都会先触发 PreToolUse Hook，对命令做校验。比如你可以只允许它执行 SELECT 查询，其他 SQL 一律拦截。</p><p>这比把“只能执行只读查询”写在 Prompt 里更可靠，因为它从工具执行层面增加了强约束。</p><p>关于 hooks 的更多细节，可以参考官方文档：<a href="https://code.claude.com/docs/zh-CN/hooks" target="_blank" rel="noreferrer">https://code.claude.com/docs/zh-CN/hooks</a></p><h2 id="subagent-工作流编排" tabindex="-1">SubAgent 工作流编排 <a class="header-anchor" href="#subagent-工作流编排" aria-label="Permalink to &quot;SubAgent 工作流编排&quot;">​</a></h2><p>理解了 SubAgent 的上下文隔离、权限控制和能力复用之后，下一步就是思考：如何根据业务场景去编排这些子代理。</p><p>实际工作里，最常见的是两种模式：</p><ul><li>并行模式</li><li>流水线模式</li></ul><h2 id="并行场景-接手一个新项目" tabindex="-1">并行场景：接手一个新项目 <a class="header-anchor" href="#并行场景-接手一个新项目" aria-label="Permalink to &quot;并行场景：接手一个新项目&quot;">​</a></h2><p>假设一位前端同学转做全栈，开始接手一个新的后端项目。为了快速理解系统，他通常需要分别摸清多个模块：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#e1e4e8;">1. 理解 Auth 模块代码：4 小时</span></span>
<span class="line"><span style="color:#e1e4e8;">2. 理解 Database 模块代码：8 小时</span></span>
<span class="line"><span style="color:#e1e4e8;">3. 理解 API 模块代码：3 小时</span></span>
<span class="line"><span style="color:#e1e4e8;"></span></span>
<span class="line"><span style="color:#e1e4e8;">综合理解：?? （我记不起来了 😩）</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292e;">1. 理解 Auth 模块代码：4 小时</span></span>
<span class="line"><span style="color:#24292e;">2. 理解 Database 模块代码：8 小时</span></span>
<span class="line"><span style="color:#24292e;">3. 理解 API 模块代码：3 小时</span></span>
<span class="line"><span style="color:#24292e;"></span></span>
<span class="line"><span style="color:#24292e;">综合理解：?? （我记不起来了 😩）</span></span></code></pre></div><p>如果完全靠人工逐个阅读，成本很高，而且每理解完一个模块，还要重新把记忆拼接起来。</p><p>在 AI 场景下，我们可以把这类任务拆给多个 SubAgent 并行完成：</p><p><img src="`+t+'" alt="并行场景编排"></p><p>例如：</p><ul><li>一个 SubAgent 负责 Auth 模块</li><li>一个 SubAgent 负责 Database 模块</li><li>一个 SubAgent 负责 API 模块</li></ul><p>它们各自完成探索后，把结构化结论返回给主 Agent，再由主 Agent 做统一整合：</p><p><img src="'+c+'" alt="并行场景编排"></p><blockquote><p>并行探索有一个隐含前提：这些子任务之间不能存在强依赖关系。</p></blockquote><h2 id="串行场景-修复-bug-流水线" tabindex="-1">串行场景：修复 Bug 流水线 <a class="header-anchor" href="#串行场景-修复-bug-流水线" aria-label="Permalink to &quot;串行场景：修复 Bug 流水线&quot;">​</a></h2><p>与并行场景不同，修复 bug 往往是一个天然分阶段的流程。</p><p>通常会经历以下几个步骤：</p><ol><li>定位问题</li><li>分析原因</li><li>实施修复</li><li>验证结果</li></ol><p>这种情况下，每一步都依赖前一步的输出，因此更适合采用流水线式的编排：</p><p><img src="'+i+'" alt="串行场景编排"></p><p>你可以让不同的 SubAgent 分别负责不同阶段，主 Agent 负责在每个阶段之间进行交接和整合。</p><p>如果所有阶段都交给主 Agent 一次性完成，那么问题定位过程、实验过程、修改过程、验证过程会全部混在同一上下文中，很容易造成注意力分散。</p><p>而使用流水线拆分后，主 Agent 只需要关注“当前阶段最需要的输入和输出”，整个修复过程会更清晰：</p><p><img src="'+r+'" alt="串行场景编排"></p><h2 id="并行-vs-流水线-怎么选" tabindex="-1">并行 vs 流水线：怎么选？ <a class="header-anchor" href="#并行-vs-流水线-怎么选" aria-label="Permalink to &quot;并行 vs 流水线：怎么选？&quot;">​</a></h2><p>判断标准其实很直接：</p><ul><li>任务之间独立吗？独立就适合并行</li><li>任务之间有依赖吗？有依赖就适合流水线</li></ul><p><img src="'+d+'" alt="并行 vs 流水线"></p><p>当然，真实场景里并不总是纯粹的并行或纯粹的串行。很多时候会是“先串行定位，再并行分析；最后再串行汇总”的混合模式。编排方式应该围绕业务依赖关系来设计，而不是为了多 Agent 而多 Agent。</p><h2 id="subagent-team-团队协作" tabindex="-1">SubAgent Team：团队协作 <a class="header-anchor" href="#subagent-team-团队协作" aria-label="Permalink to &quot;SubAgent Team：团队协作&quot;">​</a></h2><p>前面提到的 SubAgent，本质上仍然是由主 Agent 调度、彼此相互隔离的执行单元。</p><p>这种方式已经能解决很多问题，但它也有一个天然限制：子代理之间通常不能直接交流。</p><p>这意味着在一些复杂问题中，不同子代理即使各自发现了关键线索，也可能因为无法互相看到对方的发现，而错过真正的交叉结论。</p><h3 id="一个典型例子" tabindex="-1">一个典型例子 <a class="header-anchor" href="#一个典型例子" aria-label="Permalink to &quot;一个典型例子&quot;">​</a></h3><p>假设你的系统出现了一个诡异 bug：用户登录后偶尔会话丢失，而且没有明显规律。你怀疑可能有三类原因：</p><ul><li>假设 A：JWT token 的过期时间计算有问题</li><li>假设 B：Redis session 存储存在竞态条件</li><li>假设 C：负载均衡器的 sticky session 配置异常</li></ul><p>如果用普通 SubAgent 处理，可能会像这样：</p><p><img src="'+u+'" alt="subAgent Team"></p><p>每个子代理都在自己的上下文里独立调查，但彼此无法直接交换发现。</p><p>比如子代理 B 如果能看到子代理 C 的发现，它可能会进一步意识到：Redis 连接数上限问题，可能不是单纯的缓存问题，而是 sticky session 在 5 分钟后切换机器，触发了新的 Redis 连接建立。</p><p>这类需要多视角交叉验证和相互挑战的问题，就是 Agent Team 要解决的场景：让多个 Agent 不只是“分别干活”，而是可以围绕同一个问题协作推进。</p><p><img src="'+y+`" alt="subAgent Team"></p><h3 id="如何启用-subagent-team" tabindex="-1">如何启用 SubAgent Team <a class="header-anchor" href="#如何启用-subagent-team" aria-label="Permalink to &quot;如何启用 SubAgent Team&quot;">​</a></h3><p>Agent Teams 默认是关闭的。启用方式是在 settings.json 中设置环境变量：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#E1E4E8;">{</span></span>
<span class="line"><span style="color:#E1E4E8;">  </span><span style="color:#79B8FF;">&quot;env&quot;</span><span style="color:#E1E4E8;">: {</span></span>
<span class="line"><span style="color:#E1E4E8;">    </span><span style="color:#79B8FF;">&quot;CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS&quot;</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">&quot;1&quot;</span></span>
<span class="line"><span style="color:#E1E4E8;">  }</span></span>
<span class="line"><span style="color:#E1E4E8;">}</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292E;">{</span></span>
<span class="line"><span style="color:#24292E;">  </span><span style="color:#005CC5;">&quot;env&quot;</span><span style="color:#24292E;">: {</span></span>
<span class="line"><span style="color:#24292E;">    </span><span style="color:#005CC5;">&quot;CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS&quot;</span><span style="color:#24292E;">: </span><span style="color:#032F62;">&quot;1&quot;</span></span>
<span class="line"><span style="color:#24292E;">  }</span></span>
<span class="line"><span style="color:#24292E;">}</span></span></code></pre></div><p>启用后，就可以用自然语言让 Claude 创建团队，例如：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#e1e4e8;">创建一个 agent team 从不同角度探索这个问题：</span></span>
<span class="line"><span style="color:#e1e4e8;">一个 teammate 负责 UX，一个负责技术架构（用最好的模型），一个扮演审评质疑者（用普通模型）。</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292e;">创建一个 agent team 从不同角度探索这个问题：</span></span>
<span class="line"><span style="color:#24292e;">一个 teammate 负责 UX，一个负责技术架构（用最好的模型），一个扮演审评质疑者（用普通模型）。</span></span></code></pre></div><p><img src="`+h+'" alt="subAgent Team 创建"></p><p>Claude 会自动创建团队、生成对应的 teammates、组织它们协作，然后在任务完成后清理团队。</p><p>团队创建成功后，一个 Agent Team 大致由以下组件组成：</p><p><img src="'+E+`" alt="subAgent Team 组成"></p><p>相关数据会保存在本地：</p><ul><li>团队配置：<code>~/.claude/teams/{team-name}/config.json</code></li><li>任务列表：<code>~/.claude/tasks/{team-name}/</code></li></ul><p>其中团队配置里的 members 数组会记录每个 teammate 的名称、agent ID 和类型。Teammates 可以基于这些信息发现彼此，从而形成真正的团队协作。</p><h2 id="从-subagent-到-multi-agent" tabindex="-1">从 SubAgent 到 Multi-Agent <a class="header-anchor" href="#从-subagent-到-multi-agent" aria-label="Permalink to &quot;从 SubAgent 到 Multi-Agent&quot;">​</a></h2><p>在 AI Agent 工程实践里，一个非常常见的误区是：过早引入多 Agent 架构。</p><p>很多时候，问题还没有复杂到需要多 Agent，你却已经开始设计调度器、角色分工、状态流转和协作协议。这样做不但不会提升效率，反而会增加系统复杂度和维护成本。</p><p>所以更合理的思路不是“一开始就做多 Agent”，而是沿着复杂度逐步演进。</p><h3 id="什么时候才需要多-agent" tabindex="-1">什么时候才需要多 Agent？ <a class="header-anchor" href="#什么时候才需要多-agent" aria-label="Permalink to &quot;什么时候才需要多 Agent？&quot;">​</a></h3><p>通常有两个核心触发条件。</p><h4 id="_1-上下文管理开始失控" tabindex="-1">1. 上下文管理开始失控 <a class="header-anchor" href="#_1-上下文管理开始失控" aria-label="Permalink to &quot;1. 上下文管理开始失控&quot;">​</a></h4><p>如果多个领域的知识无法舒适地塞进同一个 Prompt，必须按角色或任务分发上下文，而不是全部堆给一个 Agent，那么就说明单 Agent 已经接近边界了。</p><h4 id="_2-需要分布式维护能力" tabindex="-1">2. 需要分布式维护能力 <a class="header-anchor" href="#_2-需要分布式维护能力" aria-label="Permalink to &quot;2. 需要分布式维护能力&quot;">​</a></h4><p>如果不同团队需要独立维护自己的 Agent 能力，比如：</p><ul><li>安全团队维护审计 Agent</li><li>测试团队维护测试 Agent</li><li>开发团队维护开发 Agent</li></ul><p>那么你面对的已经不只是一个 Prompt 优化问题，而是一个跨团队能力协作问题。这时多 Agent 架构才真正有意义。</p><p>可以把单 Agent 的困境想象成下面这样：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#e1e4e8;">单 Agent 的困境：</span></span>
<span class="line"><span style="color:#e1e4e8;">┌─────────────────────────────────────────────────┐</span></span>
<span class="line"><span style="color:#e1e4e8;">│ System Prompt:                                  │</span></span>
<span class="line"><span style="color:#e1e4e8;">│   - 你是代码专家（200行指令）                    │</span></span>
<span class="line"><span style="color:#e1e4e8;">│   - 你也是测试专家（150行指令）                  │</span></span>
<span class="line"><span style="color:#e1e4e8;">│   - 你还是安全审计专家（180行指令）              │</span></span>
<span class="line"><span style="color:#e1e4e8;">│   - 你同时是文档撰写专家（100行指令）            │</span></span>
<span class="line"><span style="color:#e1e4e8;">│   ...                                           │</span></span>
<span class="line"><span style="color:#e1e4e8;">│   Token 爆炸，模型注意力分散                    │</span></span>
<span class="line"><span style="color:#e1e4e8;">└─────────────────────────────────────────────────┘</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292e;">单 Agent 的困境：</span></span>
<span class="line"><span style="color:#24292e;">┌─────────────────────────────────────────────────┐</span></span>
<span class="line"><span style="color:#24292e;">│ System Prompt:                                  │</span></span>
<span class="line"><span style="color:#24292e;">│   - 你是代码专家（200行指令）                    │</span></span>
<span class="line"><span style="color:#24292e;">│   - 你也是测试专家（150行指令）                  │</span></span>
<span class="line"><span style="color:#24292e;">│   - 你还是安全审计专家（180行指令）              │</span></span>
<span class="line"><span style="color:#24292e;">│   - 你同时是文档撰写专家（100行指令）            │</span></span>
<span class="line"><span style="color:#24292e;">│   ...                                           │</span></span>
<span class="line"><span style="color:#24292e;">│   Token 爆炸，模型注意力分散                    │</span></span>
<span class="line"><span style="color:#24292e;">└─────────────────────────────────────────────────┘</span></span></code></pre></div><h3 id="multi-agent-的架构演进路径" tabindex="-1">Multi-Agent 的架构演进路径 <a class="header-anchor" href="#multi-agent-的架构演进路径" aria-label="Permalink to &quot;Multi-Agent 的架构演进路径&quot;">​</a></h3><h4 id="_1-单一-agent-架构" tabindex="-1">1. 单一 Agent 架构 <a class="header-anchor" href="#_1-单一-agent-架构" aria-label="Permalink to &quot;1. 单一 Agent 架构&quot;">​</a></h4><p>适合大多数起步阶段的简单场景。一开始没有必要为了“先进架构”而过早拆分。</p><p><img src="`+g+'" alt="单一 Agent 架构"></p><h4 id="_2-单-agent-skills" tabindex="-1">2. 单 Agent + Skills <a class="header-anchor" href="#_2-单-agent-skills" aria-label="Permalink to &quot;2. 单 Agent + Skills&quot;">​</a></h4><p>当 Tools 越来越多、Prompt 越来越大时，可以先通过 Skills 做渐进式能力加载，而不是把所有能力一次性塞进系统提示中。</p><p><img src="'+b+'" alt="单 Agent + Skills 架构"></p><h4 id="_3-supervisor-多个子-agent" tabindex="-1">3. Supervisor + 多个子 Agent <a class="header-anchor" href="#_3-supervisor-多个子-agent" aria-label="Permalink to &quot;3. Supervisor + 多个子 Agent&quot;">​</a></h4><p>当业务开始涉及多领域知识、上下文隔离、权限控制、任务拆分时，再演进到 Supervisor + 多个 SubAgent 的结构。</p><p><img src="'+m+'" alt="Supervisor + 多个子 Agent 架构"></p><h4 id="_4-混合架构" tabindex="-1">4. 混合架构 <a class="header-anchor" href="#_4-混合架构" aria-label="Permalink to &quot;4. 混合架构&quot;">​</a></h4><p>成熟系统中，往往不是只使用一种模式，而是组合使用：</p><ul><li>Router 负责分类</li><li>Sub-Agent 负责并行研究</li><li>Handoff 负责顺序流转</li></ul><p><img src="'+A+`" alt="混合架构"></p><h3 id="如何判断是否应该引入多-agent" tabindex="-1">如何判断是否应该引入多 Agent？ <a class="header-anchor" href="#如何判断是否应该引入多-agent" aria-label="Permalink to &quot;如何判断是否应该引入多 Agent？&quot;">​</a></h3><p>可以参考下面这套简单决策逻辑：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#e1e4e8;">你的任务需要多 Agent 吗？</span></span>
<span class="line"><span style="color:#e1e4e8;">├─ 单一领域、工具 &lt; 5 个、上下文 &lt; 50K tokens</span></span>
<span class="line"><span style="color:#e1e4e8;">│  └─→ 不需要。用单 Agent + 好的 Prompt 即可</span></span>
<span class="line"><span style="color:#e1e4e8;">│</span></span>
<span class="line"><span style="color:#e1e4e8;">├─ 单一领域、但工具 &gt; 10 个</span></span>
<span class="line"><span style="color:#e1e4e8;">│  └─→ 考虑 Skills 模式（渐进式能力加载）</span></span>
<span class="line"><span style="color:#e1e4e8;">│</span></span>
<span class="line"><span style="color:#e1e4e8;">├─ 多领域、各领域需要独立上下文</span></span>
<span class="line"><span style="color:#e1e4e8;">│  └─→ 使用 Sub-Agents 模式</span></span>
<span class="line"><span style="color:#e1e4e8;">│</span></span>
<span class="line"><span style="color:#e1e4e8;">├─ 需要多步骤状态流转（如客服工单流程）</span></span>
<span class="line"><span style="color:#e1e4e8;">│  └─→ 使用 Handoffs 模式</span></span>
<span class="line"><span style="color:#e1e4e8;">│</span></span>
<span class="line"><span style="color:#e1e4e8;">└─ 需要跨多个数据源并行查询</span></span>
<span class="line"><span style="color:#e1e4e8;">   └─→ 使用 Router 模式</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292e;">你的任务需要多 Agent 吗？</span></span>
<span class="line"><span style="color:#24292e;">├─ 单一领域、工具 &lt; 5 个、上下文 &lt; 50K tokens</span></span>
<span class="line"><span style="color:#24292e;">│  └─→ 不需要。用单 Agent + 好的 Prompt 即可</span></span>
<span class="line"><span style="color:#24292e;">│</span></span>
<span class="line"><span style="color:#24292e;">├─ 单一领域、但工具 &gt; 10 个</span></span>
<span class="line"><span style="color:#24292e;">│  └─→ 考虑 Skills 模式（渐进式能力加载）</span></span>
<span class="line"><span style="color:#24292e;">│</span></span>
<span class="line"><span style="color:#24292e;">├─ 多领域、各领域需要独立上下文</span></span>
<span class="line"><span style="color:#24292e;">│  └─→ 使用 Sub-Agents 模式</span></span>
<span class="line"><span style="color:#24292e;">│</span></span>
<span class="line"><span style="color:#24292e;">├─ 需要多步骤状态流转（如客服工单流程）</span></span>
<span class="line"><span style="color:#24292e;">│  └─→ 使用 Handoffs 模式</span></span>
<span class="line"><span style="color:#24292e;">│</span></span>
<span class="line"><span style="color:#24292e;">└─ 需要跨多个数据源并行查询</span></span>
<span class="line"><span style="color:#24292e;">   └─→ 使用 Router 模式</span></span></code></pre></div><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>SubAgent 并不是为了“看起来更高级”，而是为了在上下文、权限和职责开始失控时，给 Agent 系统增加必要的结构化能力。</p><p>你可以把它理解成一套逐步升级的工程策略：</p><ul><li>先用单 Agent 解决问题</li><li>当 Prompt 和 Tools 开始膨胀时，引入 Skills</li><li>当任务需要上下文隔离和权限控制时，引入 SubAgent</li><li>当问题需要真正的多角色协作时，再考虑 Agent Team 或更完整的 Multi-Agent 架构</li></ul><p>真正好的 SubAgent，不只是“能跑”，而是边界清晰、职责明确、容易复用、便于团队协作。</p><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://code.claude.com/docs/zh-CN/sub-agents" target="_blank" rel="noreferrer">SubAgent 官方文档</a></li><li><a href="https://www.anthropic.com/engineering/effective-context-engineering-for-ai-agents" target="_blank" rel="noreferrer">Effective context engineering for AI agents</a></li><li><a href="https://www.anthropic.com/engineering/multi-agent-architecture-in-ai-agent-engineering" target="_blank" rel="noreferrer">Multi-Agent Architecture in AI Agent Engineering</a></li><li><a href="https://code.claude.com/docs/zh-CN/agent-teams" target="_blank" rel="noreferrer">SubAgent Team</a></li></ul>`,188),f=[v];function _(q,C,F,P,S,w){return a(),n("div",null,f)}const D=s(k,[["render",_]]);export{B as __pageData,D as default};
